    let mut local = c2::C0::new(c.rows.len().max(1));
    let moved = b1::bx(&mut h, &c.seq);
    let base_rows: Vec<Vec<i32>> = c.rows.iter().enumerate().map(|(i, row)| {
        if c.packed { a0::ax(&meta, row, i) } else { row.clone() }
